-- Migration: seed the AI Governance & Risk Management I - AI (AIGRM-I) certification.
--
-- FOUNDS the 'governance' cert category (family #2) and stands up the full
-- AIGRM-I skeleton from AIGRM-I_JTA_v1 (LOCKED, Grok 9.1/10):
--   governance category -> certification row -> 5 domains -> 49 tasks (with KSAs)
--   -> 165 concepts -> every task_concepts link, written in THIS migration.
--
-- First credential in the Governance family; first non-Scrum cert on the platform.
-- Signature domain D4 (The AI Lifecycle & Accountable Deployment, 25%) carries the
-- agentic-accountability capstone. cert id 55555555-... continues the repeating-digit
-- convention (SM 1111, GAIPC 2222, SPO 3333, SD 4444, AIGRM 5555).
--
-- status = 'draft' (hidden) and is_published = false: AIGRM-I stays dark until it has
-- lessons + both question pools. Promote to coming_soon / available later via set-cert-status.
--
-- NOTE (doc reconciliation): AIGRM-I_JTA_v1.md summary line says 164 concepts; the
-- authoritative task tables specify 165 (D1 has 31, not the 30 the summary claimed).
-- This migration seeds the correct 165. The JTA summary line should be corrected to match.
--
-- Reachability baked in from row one: task_concepts populated at creation.
-- Idempotent: section 2 wipes ONLY this cert's children (scoped to 5555...), then reseeds.
-- Editor-first: run top-to-bottom in the SQL Editor, then commit this file.
-- Prose is ASCII-only and dollar-quoted ($$...$$) to avoid multibyte paste corruption.

-- =====================================================================
-- SECTION 0 - Cert category (FOUND the 'governance' family; upsert by slug)
-- =====================================================================
insert into public.cert_categories (slug, label, tagline, sort_order) values
  ('governance','Certidemy Governance',$$Governing AI and risk in the enterprise - responsibly, and by design.$$,4)
on conflict (slug) do update
  set label = excluded.label, tagline = excluded.tagline, sort_order = excluded.sort_order;

-- =====================================================================
-- SECTION 1 - Certification (upsert by fixed id)
-- =====================================================================
insert into certifications (
  id, code, name, provider, description,
  exam_duration_minutes, passing_score_pct, num_questions,
  difficulty_level, tier, is_published, category_slug, sort_order, status
)
values (
  '55555555-5555-5555-5555-555555555555',
  'AIGRM-I',
  $$Certidemy AI Governance & Risk Management I - AI$$,
  'Certidemy',
  $$AI-era-native governance and risk-management certification. Validates that the holder can govern AI responsibly in an organization - AI risk, the regulatory and standards landscape, governance across the AI lifecycle, and the human and ethical practices that keep AI trustworthy - with generative and agentic AI treated as first-class throughout. Grounded in public frameworks (NIST AI RMF, EU AI Act, ISO/IEC 42001 family, OECD AI Principles); built to the ISO/IEC 17024 framework, audit-ready by design.$$,
  90, 80.00, 80,
  1, 1, false, 'governance', 1, 'draft'
)
on conflict (id) do update set
  code = excluded.code, name = excluded.name, provider = excluded.provider,
  description = excluded.description, exam_duration_minutes = excluded.exam_duration_minutes,
  passing_score_pct = excluded.passing_score_pct, num_questions = excluded.num_questions,
  difficulty_level = excluded.difficulty_level, tier = excluded.tier,
  is_published = excluded.is_published, category_slug = excluded.category_slug,
  sort_order = excluded.sort_order, status = excluded.status, updated_at = now();

-- =====================================================================
-- SECTION 2 - Idempotency reset (scoped strictly to AIGRM-I)
-- =====================================================================
delete from task_concepts where task_id in (select id from tasks where certification_id = '55555555-5555-5555-5555-555555555555');
delete from tasks    where certification_id = '55555555-5555-5555-5555-555555555555';
delete from concepts where certification_id = '55555555-5555-5555-5555-555555555555';
delete from domains  where certification_id = '55555555-5555-5555-5555-555555555555';

-- =====================================================================
-- SECTION 3 - Domains (5)
-- =====================================================================
insert into domains (certification_id, code, title, description, weight_pct, order_index)
values
  ('55555555-5555-5555-5555-555555555555','D1',$$Foundations of AI Governance & Trustworthy AI$$,$$The shared vocabulary and mental model the credential builds on: what AI governance, risk, and compliance are and how they differ; core AI terms; risk versus harm; the value-chain actors; the characteristics of trustworthy AI; why autonomy and scale raise the governance stakes; and the types of governance instrument. Predominantly comprehension, making the applied domains legible.$$,15.0,1),
  ('55555555-5555-5555-5555-555555555555','D2',$$AI Risk Management in Practice$$,$$The applied core: how AI risk is actually managed. The Govern/Map/Measure/Manage cycle, the identify-analyze-evaluate-treat process, characterizing and treating risk, and the concrete AI-era risk types - the generative taxonomy, agentic risks, security-oriented risks, model drift, and human oversight as a control. Carries the heaviest apply/analyze load.$$,22.5,2),
  ('55555555-5555-5555-5555-555555555555','D3',$$Regulatory & Standards Landscape$$,$$Orient the practitioner in the instruments that govern AI - the EU AI Act's risk-tier structure and obligation types, ISO/IEC 42001 and its family, the NIST AI RMF as a voluntary framework, and the emerging jurisdictional pattern - and how they relate. Taught strictly as structure and obligations, never as compliance advice and never implying Certidemy is any of them.$$,20.0,3),
  ('55555555-5555-5555-5555-555555555555','D4',$$The AI Lifecycle & Accountable Deployment$$,$$The signature domain: governance across the AI lifecycle, the accountability at each stage, AI system impact assessment, documentation and provenance, human oversight in live systems, incident response and post-market monitoring, third-party AI, and the AI-era capstone of accountability in agentic workflows. The richest domain; most apply/analyze.$$,25.0,4),
  ('55555555-5555-5555-5555-555555555555','D5',$$Responsible AI, Ethics & the Governance Function$$,$$The human and organizational layer that sustains everything else: the ethical principles, fairness/transparency/privacy as duties, and how a real governance function is built and kept alive - roles, policy, literacy, culture. Comprehension-led with an analytic capstone tying ethics, policy, and function into sustained trustworthy AI.$$,17.5,5);

