  ('55555555-5555-5555-5555-555555555555','supply-chain-accountability',$$Supply-Chain Accountability$$,$$Accountability persists even when AI is procured, not built in-house.$$),
  ('55555555-5555-5555-5555-555555555555','agentic-accountability',$$Agentic Accountability$$,$$Who remains accountable when an autonomous agent takes action.$$),
  ('55555555-5555-5555-5555-555555555555','accountability-cannot-be-delegated',$$Accountability Cannot Be Delegated$$,$$Accountability for AI-assisted work cannot be handed to the tool.$$),
  ('55555555-5555-5555-5555-555555555555','meaningful-human-control',$$Meaningful Human Control$$,$$Retaining genuine control over consequential autonomous action.$$),
  ('55555555-5555-5555-5555-555555555555','responsible-decommissioning',$$Responsible Decommissioning$$,$$Safely retiring an AI system.$$),
  ('55555555-5555-5555-5555-555555555555','change-management',$$Change Management$$,$$Governing significant changes to a deployed system.$$),
  ('55555555-5555-5555-5555-555555555555','responsible-ai-principles',$$Responsible-AI Principles$$,$$The core principles guiding ethical AI development and use.$$),
  ('55555555-5555-5555-5555-555555555555','human-centered-ai',$$Human-Centered AI$$,$$AI designed to serve human values, rights, and wellbeing.$$),
  ('55555555-5555-5555-5555-555555555555','beneficence-nonmaleficence',$$Beneficence and Non-Maleficence$$,$$Doing good and avoiding harm as ethical anchors for AI.$$),
  ('55555555-5555-5555-5555-555555555555','fairness-in-ai',$$Fairness in AI$$,$$Equitable treatment across individuals and groups.$$),
  ('55555555-5555-5555-5555-555555555555','sources-of-bias',$$Sources of Bias$$,$$How bias enters AI via data, design, and deployment.$$),
  ('55555555-5555-5555-5555-555555555555','bias-mitigation',$$Bias Mitigation$$,$$Measuring and reducing harmful bias.$$),
  ('55555555-5555-5555-5555-555555555555','transparency-duty',$$Transparency Duty$$,$$The obligation to be open about AI use and behavior.$$),
  ('55555555-5555-5555-5555-555555555555','explainability-for-stakeholders',$$Explainability for Stakeholders$$,$$Providing explanations appropriate to the audience.$$),
  ('55555555-5555-5555-5555-555555555555','meaningful-information',$$Meaningful Information$$,$$Giving affected people usable information about AI decisions affecting them.$$),
  ('55555555-5555-5555-5555-555555555555','privacy-beyond-compliance',$$Privacy Beyond Compliance$$,$$Treating privacy as an ethical commitment, not just the legal minimum.$$),
  ('55555555-5555-5555-5555-555555555555','privacy-by-design',$$Privacy by Design$$,$$Building privacy protections into AI systems from the start.$$),
  ('55555555-5555-5555-5555-555555555555','data-minimization',$$Data Minimization$$,$$Collecting and retaining only the data actually needed.$$),
  ('55555555-5555-5555-5555-555555555555','ai-governance-function',$$AI Governance Function$$,$$The organizational structure that owns and coordinates AI governance.$$),
  ('55555555-5555-5555-5555-555555555555','governance-roles-raci',$$Governance Roles (RACI)$$,$$Defined roles and responsibilities (RACI) for AI governance.$$),
  ('55555555-5555-5555-5555-555555555555','ai-governance-committee',$$AI Governance Committee$$,$$A cross-functional body overseeing consequential AI decisions.$$),
  ('55555555-5555-5555-5555-555555555555','ai-policy',$$AI Policy$$,$$The organization's documented commitment and rules for AI.$$),
  ('55555555-5555-5555-5555-555555555555','policy-to-practice',$$Policy to Practice$$,$$How policy translates into day-to-day AI decisions.$$),
  ('55555555-5555-5555-5555-555555555555','acceptable-use-ai',$$Acceptable-Use (AI)$$,$$Rules defining permissible AI use within the organization.$$),
  ('55555555-5555-5555-5555-555555555555','ai-literacy',$$AI Literacy$$,$$Workforce understanding of AI capabilities, limits, and risks.$$),
  ('55555555-5555-5555-5555-555555555555','training-and-culture',$$Training and Culture$$,$$Building a risk-aware, responsible AI culture.$$),
  ('55555555-5555-5555-5555-555555555555','role-based-ai-training',$$Role-Based AI Training$$,$$Training tailored to each role's AI responsibilities.$$),
  ('55555555-5555-5555-5555-555555555555','sustaining-trustworthy-ai',$$Sustaining Trustworthy AI$$,$$How ethics, policy, function, and review sustain trust over time.$$),
  ('55555555-5555-5555-5555-555555555555','continuous-improvement-governance',$$Continuous-Improvement Governance$$,$$Governance as an ongoing, improving practice.$$),
  ('55555555-5555-5555-5555-555555555555','governance-maturity',$$Governance Maturity$$,$$The progression from ad-hoc to systematic AI governance.$$);

-- =====================================================================
-- SECTION 5 - Tasks (49). domain_id resolved by domain code.
-- order_index is globally sequential 1..49.
-- =====================================================================
insert into tasks (certification_id, domain_id, code, statement, criticality, frequency, bloom_level, is_exam_scope, is_simulation_candidate, knowledge, skills, abilities, order_index)
select '55555555-5555-5555-5555-555555555555', d.id, v.code, v.statement,
       v.criticality::criticality, v.frequency::task_frequency, v.bloom::bloom_level,
       true, v.sim, v.knowledge, v.skills, v.abilities, v.order_index
from (values
  ('D1','1.1',$$Distinguish AI governance, AI risk management, and AI compliance, and explain why an organization needs all three.$$,'high','per_exam','2_understand',false,$$Governance directs and holds accountable; risk management works specific systems; compliance evidences conformance to law/standards/policy.$$,$$Separate the three when a scenario blurs them; name which is missing.$$,$$Precision about organizational responsibilities.$$,1),
  ('D1','1.2',$$Define the core AI terms and place a given system among them.$$,'high','occasional','2_understand',false,$$AI system, model, foundation/general-purpose model, generative AI, agentic AI, and how they differ.$$,$$Classify a described system by type.$$,$$Comfort with fast-moving terminology.$$,2),
  ('D1','1.3',$$Explain the difference between an AI risk and an AI harm, and identify the categories of harm an AI system can cause.$$,'high','per_exam','2_understand',false,$$A harm is a realized negative impact; a risk is its possibility, characterized by likelihood and severity; harms span individuals, groups, organizations, society.$$,$$Separate risk from harm in a scenario; categorize a described harm.$$,$$Concern for those affected by AI.$$,3),
  ('D1','1.4',$$Identify the actors in the AI value chain and how their responsibilities differ.$$,'high','per_exam','2_understand',false,$$Provider/developer, deployer, distributor, importer, affected person; obligations differ by role.$$,$$Assign the right role to an actor in a scenario.$$,$$Fairness in allocating responsibility.$$,4),
  ('D1','1.5',$$Describe the characteristics of trustworthy AI and what each means in practice.$$,'high','occasional','2_understand',false,$$Validity/reliability, safety, security/resilience, accountability/transparency, explainability/interpretability, privacy, fairness-with-bias-managed, taken together.$$,$$Match a described shortfall to the trustworthy-AI characteristic it violates.$$,$$Holistic view of what makes AI worthy of trust.$$,5),
  ('D1','1.6',$$Explain why governance matters more, not less, as AI becomes generative and agentic.$$,'high','occasional','3_apply',false,$$Autonomy, scale, and opacity raise the stakes; cheap generation and autonomous action make oversight and accountability more important.$$,$$Reason from a generative/agentic scenario to why oversight increases.$$,$$Resisting the assumption that better AI needs less governance.$$,6),
  ('D1','1.7',$$Distinguish the types of governance instrument and what each is for.$$,'medium','occasional','2_understand',false,$$Voluntary framework vs binding regulation vs management-system standard, and the purpose of each.$$,$$Classify a named instrument by type.$$,$$Clarity about what each instrument can and cannot do.$$,7),
  ('D1','1.8',$$Explain what an AI management system (AIMS) is, and how org-level governance differs from single-system risk work.$$,'medium','occasional','2_understand',false,$$An AIMS is the auditable organizational system for governing AI; org-level governance differs from managing one system's risk.$$,$$Separate org-level from project-level concerns in a scenario.$$,$$Systems thinking about the whole organization.$$,8),
  ('D2','2.1',$$Explain the purpose and structure of an AI risk-management framework, including Govern, Map, Measure, and Manage.$$,'high','occasional','2_understand',false,$$A structured, repeatable framework; the four functions Govern (cross-cutting), Map, Measure, Manage.$$,$$Assign an activity to the correct function.$$,$$Preference for structure over ad-hoc risk handling.$$,9),
  ('D2','2.2',$$Apply the risk process to a described AI use case.$$,'high','weekly','3_apply',false,$$Identify, analyze, evaluate, treat; the process iterates across the lifecycle.$$,$$Walk a use case through the four process steps.$$,$$Discipline in following a repeatable process.$$,10),
  ('D2','2.3',$$Characterize an AI risk by its likelihood and severity and prioritize among competing risks.$$,'high','weekly','3_apply',false,$$Likelihood x severity; prioritization; residual risk after treatment.$$,$$Rank risks and identify residual risk.$$,$$Proportionality; focusing effort where it matters.$$,11),
  ('D2','2.4',$$Explain risk tolerance and how it determines which AI risks an organization accepts.$$,'medium','occasional','2_understand',false,$$Risk tolerance sets the acceptable/unacceptable threshold in pursuit of objectives.$$,$$Judge a risk against a stated tolerance.$$,$$Respect for organizational risk appetite.$$,12),
  ('D2','2.5',$$Select an appropriate risk-treatment option for a given AI risk.$$,'high','weekly','3_apply',false,$$Avoid, mitigate, transfer, accept; select controls proportionate to the risk.$$,$$Choose and justify a treatment for a described risk.$$,$$Decisiveness balanced with proportionality.$$,13),
  ('D2','2.6',$$Identify the categories of generative-AI risk and recognize them in a scenario.$$,'high','weekly','3_apply',false,$$Confabulation, harmful bias, information integrity, data privacy, IP/provenance, harmful content.$$,$$Name the generative-risk category present in a scenario.$$,$$Vigilance toward generative-AI failure modes.$$,14),
  ('D2','2.7',$$Analyze the distinctive risks of agentic AI and why human oversight is required.$$,'high','occasional','4_analyze',false,$$Autonomy, tool misuse, compounding actions; why consequential autonomy demands a human check.$$,$$Trace how an agent's autonomy amplifies a failure and where oversight belongs.$$,$$Healthy caution toward autonomous action.$$,15),
  ('D2','2.8',$$Explain the security-oriented risks of AI systems and that mitigations exist.$$,'high','occasional','3_apply',false,$$Prompt injection, jailbreaks, training-data leakage, adversarial input; controls reduce but do not eliminate them.$$,$$Recognize a security-oriented AI risk and name a class of mitigation.$$,$$Security-mindedness without false certainty.$$,16),
  ('D2','2.9',$$Explain model drift and the need for ongoing monitoring of deployed AI.$$,'medium','occasional','2_understand',false,$$Drift is performance degradation as conditions change; ongoing monitoring detects it.$$,$$Spot drift risk in a described deployment.$$,$$Attentiveness to systems after launch.$$,17),
  ('D2','2.10',$$Explain human oversight as a primary control for consequential AI.$$,'high','weekly','2_understand',false,$$Human-in-the-loop and human-on-the-loop as designed, primary controls.$$,$$Choose the oversight mode fitting a consequential decision.$$,$$Insistence on human judgment where it counts.$$,18),
  ('D2','2.11',$$Explain how AI risk integrates with enterprise risk rather than standing alone.$$,'medium','occasional','2_understand',false,$$AI risk is managed within broader enterprise risk; it overlaps privacy, security, safety.$$,$$Connect an AI risk to the enterprise-risk domain it touches.$$,$$Integrative rather than siloed thinking.$$,19),
  ('D3','3.1',$$Explain the EU AI Act's risk-based structure and its four risk tiers.$$,'high','per_exam','2_understand',false,$$Risk-based approach; unacceptable/prohibited, high, limited/transparency, minimal tiers.$$,$$Place a use case in the correct risk tier.$$,$$Accuracy about a binding legal framework.$$,20),
  ('D3','3.2',$$Given a described AI system, determine whether it is high-risk under the EU AI Act and identify the obligations that attach.$$,'high','occasional','3_apply',false,$$High-risk obligations: risk-management system, data governance, technical documentation, human oversight, accuracy/robustness/cybersecurity, conformity assessment.$$,$$Decide high-risk status for a system and list the obligations that follow.$$,$$Care in applying legal criteria to a real case.$$,21),
  ('D3','3.3',$$Explain the transparency obligations for limited-risk AI.$$,'medium','occasional','2_understand',false,$$Disclose AI interaction; label synthetic content; disclose deepfakes.$$,$$Identify which transparency duty a scenario triggers.$$,$$Honesty toward end users.$$,22),
  ('D3','3.4',$$Distinguish provider vs deployer obligations under the EU AI Act.$$,'medium','occasional','3_apply',false,$$Providers develop/place systems; deployers use them; each carries distinct obligations.$$,$$Assign an obligation to provider or deployer in a scenario.$$,$$Fairness in allocating duties.$$,23),
  ('D3','3.5',$$Explain the EU AI Act's treatment of general-purpose AI (GPAI) models.$$,'medium','occasional','2_understand',false,$$GPAI transparency/documentation obligations; systemic-risk models carry additional duties.$$,$$Recognize when GPAI-specific obligations apply.$$,$$Currency with evolving GPAI rules.$$,24),
  ('D3','3.6',$$Explain what ISO/IEC 42001 is and what certification to it signals.$$,'high','per_exam','2_understand',false,$$The certifiable AI management system standard; certification signals an audited AIMS; dual mandatory risk + impact assessment.$$,$$Explain what an ISO 42001 certificate does and does not attest.$$,$$Respect for independent assurance.$$,25),
  ('D3','3.7',$$Recognize the companion ISO/IEC AI standards and their roles.$$,'medium','occasional','2_understand',false,$$23894 (risk), 42005 (impact assessment), 38507 (governance), 22989 (terminology) around 42001.$$,$$Match a companion standard to its purpose.$$,$$Orientation within a standards family.$$,26),
  ('D3','3.8',$$Explain how the NIST AI RMF complements binding law and standards.$$,'medium','occasional','2_understand',false,$$A voluntary, sector-neutral framework that complements binding law and certifiable standards.$$,$$Position NIST AI RMF relative to law and standards.$$,$$Even-handedness across instruments.$$,27),
  ('D3','3.9',$$Recognize the emerging pattern of AI regulation beyond the EU.$$,'medium','occasional','2_understand',false,$$US state laws, sectoral rules, and OECD principles as a shared baseline; a shifting patchwork.$$,$$Recognize the pattern rather than any single statute's detail.$$,$$Comfort with legal uncertainty and change.$$,28),
  ('D3','3.10',$$Analyze how the frameworks reinforce one another.$$,'high','occasional','4_analyze',false,$$Where voluntary framework, binding law, and management standard overlap; ISO 42001 supports EU-Act readiness (not automatic compliance); defense in depth.$$,$$Explain how two instruments combine to strengthen governance.$$,$$Synthesis across instruments.$$,29),
  ('D4','4.1',$$Explain the stages of the AI system lifecycle and why governance applies at each.$$,'high','per_exam','2_understand',false,$$Design, data, development, validation, deployment, monitoring, retirement; governance is continuous.$$,$$Place a governance activity at the right lifecycle stage.$$,$$End-to-end ownership mindset.$$,30),
  ('D4','4.2',$$Identify the accountability and decisions that belong at each lifecycle stage.$$,'high','weekly','3_apply',false,$$Stage accountability, gate reviews, and go/no-go decision points.$$,$$Assign an owner and a gate decision to a stage.$$,$$Clarity about who decides what, when.$$,31),
  ('D4','4.3',$$Explain the purpose of an AI system impact assessment and when it is performed.$$,'high','per_exam','2_understand',false,$$Evaluates effects on people; distinct from risk assessment; performed early and updated across the lifecycle.$$,$$Explain why and when an impact assessment is done.$$,$$Concern for real-world effects on people.$$,32),
  ('D4','4.4',$$Apply an impact-assessment mindset to a described AI system.$$,'high','occasional','3_apply',false,$$Who is affected, what could go wrong, what safeguards; foreseeable misuse.$$,$$Produce affected-parties, failure modes, and safeguards for a system.$$,$$Anticipatory, stakeholder-centered thinking.$$,33),
  ('D4','4.5',$$Explain the role of technical documentation, model cards, and system cards in accountable AI.$$,'medium','occasional','2_understand',false,$$Documentation as the substrate of accountability; model cards and system cards.$$,$$Identify what belongs in a model or system card.$$,$$Diligence in record-keeping.$$,34),
  ('D4','4.6',$$Explain data governance across the lifecycle.$$,'high','per_exam','2_understand',false,$$Provenance, quality and representativeness, consent and rights.$$,$$Spot a data-governance gap in a scenario.$$,$$Stewardship of data and the people behind it.$$,35),
  ('D4','4.7',$$Explain content provenance and authenticity for generated content.$$,'medium','occasional','2_understand',false,$$Content provenance; synthetic-content labeling; authenticity standards (e.g., C2PA-style).$$,$$Recommend a provenance measure for generated media.$$,$$Commitment to an authentic information ecosystem.$$,36),
  ('D4','4.8',$$Analyze how human oversight is designed into a deployed system.$$,'high','occasional','4_analyze',false,$$Oversight points, override, escalation; in-the-loop vs on-the-loop by consequence.$$,$$Design oversight points and escalation for a described deployment.$$,$$Insistence on real, not nominal, human control.$$,37),
  ('D4','4.9',$$Explain post-market monitoring and incident response for deployed AI.$$,'high','weekly','3_apply',false,$$Post-market monitoring, incident response, serious-incident reporting.$$,$$Outline a monitoring-and-response plan for a deployed system.$$,$$Readiness for things going wrong.$$,38),
  ('D4','4.10',$$Explain the governance of third-party and procured AI.$$,'high','occasional','2_understand',false,$$Vendor assessment; supply-chain accountability persists when AI is procured.$$,$$Identify what to assess before adopting a vendor's AI.$$,$$Accountability that does not stop at the vendor's door.$$,39),
  ('D4','4.11',$$Analyze accountability in agentic workflows.$$,'high','occasional','4_analyze',false,$$Who remains accountable when an agent acts; accountability cannot be delegated to the tool; meaningful human control.$$,$$Locate where human accountability sits in an agentic workflow.$$,$$Refusal to let the tool absorb responsibility.$$,40),
  ('D4','4.12',$$Explain responsible decommissioning and change management for AI systems.$$,'medium','occasional','2_understand',false,$$Safe retirement; governing significant changes to a deployed system.$$,$$Identify decommissioning and change-control steps.$$,$$Care through the end of the lifecycle.$$,41),
  ('D5','5.1',$$Explain the core principles of responsible AI.$$,'high','per_exam','2_understand',false,$$Human-centered, fairness, transparency, accountability, privacy, robustness; beneficence and non-maleficence.$$,$$Match a practice to the responsible-AI principle it serves.$$,$$Principled commitment beyond the minimum.$$,42),
  ('D5','5.2',$$Explain fairness and bias as an ethical and practical concern, and how bias enters AI systems.$$,'high','weekly','3_apply',false,$$Fairness; sources of bias in data, design, deployment; bias mitigation.$$,$$Trace where bias entered a described system and how to mitigate it.$$,$$Commitment to equitable outcomes.$$,43),
  ('D5','5.3',$$Explain transparency and explainability as duties to affected people.$$,'medium','occasional','2_understand',false,$$Transparency duty; audience-appropriate explainability; meaningful information for affected people.$$,$$Judge whether an explanation meets a stakeholder's needs.$$,$$Respect for people's right to understand.$$,44),
  ('D5','5.4',$$Explain privacy as a responsible-AI concern beyond legal compliance.$$,'medium','occasional','2_understand',false,$$Privacy beyond compliance; privacy by design; data minimization.$$,$$Recommend a privacy-by-design measure for a system.$$,$$Care for personal data as an ethical duty.$$,45),
  ('D5','5.5',$$Given an organization's context, determine an appropriate AI governance-function structure.$$,'high','occasional','3_apply',false,$$Roles, a governance committee, and RACI fit to the organization's context.$$,$$Propose a fit-for-context governance structure.$$,$$Pragmatism about what an organization can actually run.$$,46),
  ('D5','5.6',$$Explain the role of an AI policy in guiding organizational AI use.$$,'medium','occasional','2_understand',false,$$An AI policy as documented commitment; policy-to-practice; acceptable-use rules.$$,$$Identify what an AI policy should cover.$$,$$Belief that stated policy must guide real decisions.$$,47),
  ('D5','5.7',$$Explain AI literacy and training as a governance obligation and culture practice.$$,'medium','occasional','2_understand',false,$$AI literacy; training-and-culture; role-based training.$$,$$Design role-appropriate AI training for a team.$$,$$Investment in people, not just controls.$$,48),
  ('D5','5.8',$$Analyze how ethics, policy, and the governance function combine to sustain trustworthy AI over time.$$,'high','occasional','4_analyze',false,$$How ethics, policy, function, and review sustain trust; continuous improvement; governance maturity.$$,$$Explain how the pieces combine to keep AI trustworthy over time.$$,$$Long-term stewardship of trust.$$,49)
) as v(domain_code, code, statement, criticality, frequency, bloom, sim, knowledge, skills, abilities, order_index)
join domains d on d.certification_id = '55555555-5555-5555-5555-555555555555' and d.code = v.domain_code;

